const express = require('express');
const app = express();
const bodyParser = require('body-parser');

app.use(bodyParser.json());

let plugins = [];

if (process.env.PLUGINS) {
  const pluginCodes = process.env.PLUGINS.split(',');
  for (const code of pluginCodes) {
    try {
      const plugin = eval(code);
      if (plugin && typeof plugin === 'object' && plugin.name) {
        plugins.push(plugin);
      }
    } catch (e) {
      console.error(`Error loading plugin: ${code}`);
    }
  }
}

if (process.env.PLUGINS_FILE) {
  try {
    const fileContent = require('fs').readFileSync(process.env.PLUGINS_FILE, 'utf8');
    const pluginCodes = fileContent.split(',');
    for (const code of pluginCodes) {
      try {
        const plugin = eval(code);
        if (plugin && typeof plugin === 'object' && plugin.name) {
          plugins.push(plugin);
        }
      } catch (e) {
        console.error(`Error loading plugin: ${code}`);
      }
    }
  } catch (e) {
    console.error(`Error reading plugins file: ${process.env.PLUGINS_FILE}`);
  }
}

app.use((req, res, next) => {
  for (const plugin of plugins) {
    const modifiedReq = plugin.modifyRequest(req);
    if (modifiedReq) {
      req = modifiedReq;
    }

    const modifiedRes = plugin.modifyResponse(res);
    if (modifiedRes) {
      res = modifiedRes;
    }
  }
  next();
});

app.use((err, req, res, next) => {
  for (const plugin of plugins) {
    const error = plugin.handleError(err);
    if (error) {
      err = error;
    }
  }
  next(err);
});

// Example plugin code
class ExamplePlugin {
  modifyRequest(req) {
    // Modify request here
    req.headers['example-header'] = 'example-value';
    return req;
  }

  modifyResponse(res) {
    // Modify response here
    res.status(200).send('Hello from example plugin!');
    return res;
  }

  handleError(err) {
    // Handle error here
    console.error(err);
    return err;
  }
}

// Register the example plugin
plugins.push(new ExamplePlugin());

app.listen(3000, () => {
  console.log('API Gateway listening on port 3000');
});